import { useState } from "react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkAdd = ({ setView, refresh }) => {
  const [name, setName] = useState("");
  const [isActive, setIsActive] =
    useState(true);

  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(API, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        name,
        isActive,
        parent: null,
      }),
    });

    setName("");
    setIsActive(true);
    refresh();
    setView("home");
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        <form
          onSubmit={handleSubmit}
          className={design.form}
        >
          <input
            type="text"
            placeholder="Link Name"
            value={name}
            onChange={(e) =>
              setName(e.target.value)
            }
            className={design.input}
            required
          />

          <select
            value={isActive}
            onChange={(e) =>
              setIsActive(
                e.target.value === "true"
              )
            }
            className={design.input}
          >
            <option value="true">
              Active
            </option>
            <option value="false">
              Inactive
            </option>
          </select>

          <div className={design.buttonGroup}>
            <button
              type="submit"
              className={design.submitButton}
            >
              Create
            </button>

            <button
              type="button"
              onClick={() =>
                setView("home")
              }
              className={design.cancelButton}
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default LinkAdd;
